t.script:
(function(){
    var l='ar';
    try{ var s=localStorage.getItem('df_lang'); if(s==='en'||s==='ar') l=s; }catch(e){}
    var w=document.getElementById('df-retail-wrap');
    if(w){ w.setAttribute('dir',l==='ar'?'rtl':'ltr'); w.classList.add('lang-'+l); }
    else{
        document.addEventListener('DOMContentLoaded',function(){
            var w2=document.getElementById('df-retail-wrap');
            if(w2){ w2.setAttribute('dir',l==='ar'?'rtl':'ltr'); w2.classList.add('lang-'+l); }
        });
    }
})();

nav.style:
position:sticky; top:0; z-index:100;
background:rgba(255,255,255,0.95);
backdrop-filter:blur(12px);
border-bottom:1px solid #e8edf5; padding:0;
